locals {
  uami_name = coalesce(var.uami_name_override, "id-${var.env_name}-wif")
  fic_name  = coalesce(var.fic_name_override, "fic-${var.service_connection_name}")

  fic_subject = "sc://${var.ado_org_name}/${var.ado_project_name}/${var.service_connection_name}"
  fic_issuer  = "https://vstoken.dev.azure.com/${var.ado_collection_id}"
}

resource "azurerm_user_assigned_identity" "this" {
  name                = local.uami_name
  resource_group_name = var.resource_group_name
  location            = var.location
  tags                = var.tags
}

resource "azurerm_federated_identity_credential" "this" {
  name                = local.fic_name
  resource_group_name = var.resource_group_name
  parent_id           = azurerm_user_assigned_identity.this.id
  audience            = ["api://AzureADTokenExchange"]
  issuer              = local.fic_issuer
  subject             = local.fic_subject
}

