variable "env_name" {
  type        = string
  description = "Environment identifier used to derive the default UAMI name (id-<env_name>-wif) and to scope the FIC. Lowercase alphanumerics and hyphens only (e.g., cafehyna-dev, packer-dev)."

  validation {
    condition     = can(regex("^[a-z0-9-]+$", var.env_name))
    error_message = "env_name must match ^[a-z0-9-]+$ (lowercase alphanumerics and hyphens)."
  }
}

variable "ado_org_name" {
  type        = string
  description = "Azure DevOps organization name (e.g., hyperadevops). Rendered into the FIC subject claim: sc://<ado_org_name>/<ado_project_name>/<service_connection_name>."

  validation {
    condition     = length(var.ado_org_name) > 0
    error_message = "ado_org_name must not be empty."
  }
}

variable "ado_project_name" {
  type        = string
  description = "Azure DevOps project name (e.g., rg-hypera-packer-image). Rendered into the FIC subject claim."

  validation {
    condition     = length(var.ado_project_name) > 0
    error_message = "ado_project_name must not be empty."
  }
}

variable "service_connection_name" {
  type        = string
  description = "Azure DevOps service connection name that will federate to this UAMI (e.g., sc-cafehyna-dev-wif). Load-bearing contract per ADR 010 §2 Decision 6 — renaming breaks the FIC with AADSTS700213."

  validation {
    condition     = length(var.service_connection_name) > 0
    error_message = "service_connection_name must not be empty."
  }
}

variable "ado_collection_id" {
  type        = string
  description = "ADO organization's collection instance ID (GUID). Used to build the FIC issuer URL: https://vstoken.dev.azure.com/<ado_collection_id>. Read-only lookup via: az devops invoke --org https://dev.azure.com/<org> --area core --resource-path connectionData --query 'instanceId' -o tsv."

  validation {
    condition     = can(regex("^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$", var.ado_collection_id))
    error_message = "ado_collection_id must be a GUID (8-4-4-4-12 hex)."
  }
}

variable "location" {
  type        = string
  description = "Azure region where the UAMI is provisioned (e.g., eastus, eastus2)."
}

variable "resource_group_name" {
  type        = string
  description = "Name of the resource group (in the UAMI's home subscription) that will hold the UAMI and its FIC."
}

